@patch
def _add_to_path(self:LODNavigator, navigation_id:str, action:str, **kwargs):
    """Add a step to the navigation path."""
    step = {
        "step": len(self.navigation_paths[navigation_id]) + 1,
        "action": action,
        **kwargs
    }
    self.navigation_paths[navigation_id].append(step)
    return step

